#!/usr/bin/env bash
set -euo pipefail

if [ "$(id -un)" != "{5}" ]; then
  exec sudo -u {5} /usr/local/bin/openclaw-approve-browser "$@"
fi

OPENCLAW_NODE_BIN="/home/{5}/.openclaw/tools/node/bin/node"
OPENCLAW_DIST_DIR="/home/{5}/.openclaw/lib/node_modules/openclaw/dist"
OPENCLAW_PAIRING_MODULE="$(find "$OPENCLAW_DIST_DIR" -maxdepth 1 -name ''device-pairing-*.js'' | head -n 1)"
PAIRING_LIST_JS_B64=""
PAIRING_APPROVE_JS_B64=""

if [ ! -x "$OPENCLAW_NODE_BIN" ]; then
  echo "OpenClaw Node runtime was not found at $OPENCLAW_NODE_BIN" >&2
  exit 1
fi

if [ -z "$OPENCLAW_PAIRING_MODULE" ]; then
  echo "OpenClaw device pairing module was not found under $OPENCLAW_DIST_DIR" >&2
  exit 1
fi

request_id=""
attempt=1
while [ "$attempt" -le 3 ]; do
	set +e
	pairing_output=$(printf ''%s'' "$PAIRING_LIST_JS_B64" | base64 -d | "$OPENCLAW_NODE_BIN" --input-type=module - "$OPENCLAW_PAIRING_MODULE" 2>&1)
	status=$?
	set -e

	request_id=$(printf "%s\n" "$pairing_output" | sed -n ''s/^OPENCLAW_REQUEST_ID://p'' | tail -n 1)

	if [ "$status" -eq 0 ] && [ -n "$request_id" ]; then
		break
	fi

	if [ "$status" -ne 2 ]; then
		printf "%s\n" "$pairing_output" >&2
		exit "$status"
	fi

	if [ "$attempt" -eq 3 ]; then
		echo "No pending browser pairing requests. Keep the dashboard page open on the pairing screen, wait a few seconds, and try again." >&2
		exit 0
	fi

	sleep 2
	attempt=$((attempt + 1))
done

echo "Approving browser pairing request: $request_id" >&2
printf ''%s'' "$PAIRING_APPROVE_JS_B64" | base64 -d | "$OPENCLAW_NODE_BIN" --input-type=module - "$OPENCLAW_PAIRING_MODULE" "$request_id"
EOF
