cat > /usr/local/bin/openclaw-gateway-mode <<''EOF''
#!/usr/bin/env bash
set -euo pipefail

ENV_FILE=/etc/openclaw/openclaw.env
OVERRIDE_FILE=/etc/openclaw/openclaw-shell-override.env

if [ ! -r "$ENV_FILE" ]; then
  echo "Missing $ENV_FILE" >&2
  exit 1
fi

set -a
. "$ENV_FILE"
set +a

case "${{OPENCLAW_PUBLIC_URL%/}}" in
  https://*)
    public_gateway_url="wss://${{OPENCLAW_PUBLIC_URL#https://}}"
    public_gateway_url="${{public_gateway_url%/}}"
    ;;
  http://*)
    public_gateway_url="ws://${{OPENCLAW_PUBLIC_URL#http://}}"
    public_gateway_url="${{public_gateway_url%/}}"
    ;;
  *)
    echo "Cannot derive a public gateway URL from OPENCLAW_PUBLIC_URL=$OPENCLAW_PUBLIC_URL" >&2
    exit 1
    ;;
esac

loopback_gateway_url="ws://127.0.0.1:${{OPENCLAW_GATEWAY_PORT}}"

OPENCLAW_NODE_BIN="$HOME/.openclaw/tools/node/bin/node"
OPENCLAW_DIST_DIR="$HOME/.openclaw/lib/node_modules/openclaw/dist"
OPENCLAW_PAIRING_MODULE="$(find "$OPENCLAW_DIST_DIR" -maxdepth 1 -name ''device-pairing-*.js'' | head -n 1)"

require_pairing_module() {{
  if [ ! -x "$OPENCLAW_NODE_BIN" ]; then
    echo "OpenClaw Node runtime was not found at $OPENCLAW_NODE_BIN" >&2
    exit 1
  fi

  if [ -z "$OPENCLAW_PAIRING_MODULE" ]; then
    echo "OpenClaw device pairing module was not found under $OPENCLAW_DIST_DIR" >&2
    exit 1
  fi
}}

read_local_device_id() {{
  "$OPENCLAW_NODE_BIN" --input-type=module - <<''NODE_ID''
const fs = await import("node:fs/promises");

const raw = JSON.parse(await fs.readFile("/data/identity/device.json", "utf8"));
const deviceId = String(raw?.deviceId || "").trim();
if (!deviceId) {{
  throw new Error("deviceId was not found in /data/identity/device.json");
}}
process.stdout.write(deviceId);
NODE_ID
}}

capture_cli_pending_request_ids() {{
  local output_file="$1"
  local target_device_id="$2"

  "$OPENCLAW_NODE_BIN" --input-type=module - "$OPENCLAW_PAIRING_MODULE" "$target_device_id" <<''NODE_CAPTURE'' | grep -E ''^[0-9a-fA-F-]{{36}}$'' > "$output_file" || true
const [modulePath, targetDeviceId] = process.argv.slice(2);
const url = await import("node:url");
const mod = await import(url.pathToFileURL(modulePath).href);
const listPairing = Object.values(mod).find(
  (value) => typeof value === "function" && value.name === "listDevicePairing",
);

if (!listPairing) {{
  throw new Error("listDevicePairing export was not found in the installed OpenClaw device pairing module.");
}}

const list = await listPairing("/data");
for (const item of list.pending || []) {{
  const requestId = String(item?.requestId || "").trim();
  const deviceId = String(item?.deviceId || "").trim();
  const role = String(item?.role || "").trim();
  const roles = Array.isArray(item?.roles) ? item.roles.map((value) => String(value)) : [];
  if (!requestId) {{
    continue;
  }}
  if (!targetDeviceId || deviceId !== targetDeviceId) {{
    continue;
  }}
  if (role !== "operator" && !roles.includes("operator")) {{
    continue;
  }}
  process.stdout.write(`${{requestId}}\n`);
}}
NODE_CAPTURE
}}

select_latest_cli_pending_request() {{
  local exclude_file="${{1:-}}"
  local target_device_id="${{2:-}}"

  "$OPENCLAW_NODE_BIN" --input-type=module - "$OPENCLAW_PAIRING_MODULE" "${{exclude_file:--}}" "$target_device_id" <<''NODE_SELECT'' | grep -E ''^[0-9a-fA-F-]{{36}}$'' | tail -n 1 || true
const [modulePath, excludePath, targetDeviceId] = process.argv.slice(2);
const fs = await import("node:fs/promises");
const url = await import("node:url");
const mod = await import(url.pathToFileURL(modulePath).href);
const listPairing = Object.values(mod).find(
  (value) => typeof value === "function" && value.name === "listDevicePairing",
);

if (!listPairing) {{
  throw new Error("listDevicePairing export was not found in the installed OpenClaw device pairing module.");
}}

const exclude = new Set();
if (excludePath && excludePath !== "-") {{
  try {{
    const contents = await fs.readFile(excludePath, "utf8");
    for (const line of contents.split(/\r?\n/)) {{
      const value = line.trim();
      if (value) {{
        exclude.add(value);
      }}
    }}
  }} catch (error) {{
    if (!(error && typeof error === "object" && "code" in error && error.code === "ENOENT")) {{
      throw error;
    }}
  }}
}}

const list = await listPairing("/data");
const matches = [];
for (const item of list.pending || []) {{
  const requestId = String(item?.requestId || "").trim();
  const deviceId = String(item?.deviceId || "").trim();
  const role = String(item?.role || "").trim();
  const roles = Array.isArray(item?.roles) ? item.roles.map((value) => String(value)) : [];
  const ts = typeof item?.ts === "number" ? item.ts : 0;
  if (!requestId || exclude.has(requestId)) {{
    continue;
  }}
  if (!targetDeviceId || deviceId !== targetDeviceId) {{
    continue;
  }}
  if (role !== "operator" && !roles.includes("operator")) {{
    continue;
  }}
  matches.push([ts, requestId]);
}}

matches.sort((left, right) => Number(left[0]) - Number(right[0]));
if (matches.length > 0) {{
  process.stdout.write(String(matches[matches.length - 1][1]));
}}
NODE_SELECT
}}

run_public_cli_probe() {{
  local timeout_ms="$1"
  local output_file="$2"
  set +e
  OPENCLAW_GATEWAY_URL="$public_gateway_url" /usr/local/bin/openclaw health --verbose --timeout "$timeout_ms" >"$output_file" 2>&1
  local status=$?
  set -e
  return "$status"
}}

approve_cli_pairing_request() {{
  local request_id="$1"
  "$OPENCLAW_NODE_BIN" --input-type=module - "$OPENCLAW_PAIRING_MODULE" "$request_id" <<''NODE_APPROVE'' >/dev/null
const [modulePath, requestId] = process.argv.slice(2);
const url = await import("node:url");
const mod = await import(url.pathToFileURL(modulePath).href);
const approvePairing = Object.values(mod).find(
  (value) => typeof value === "function" && value.name === "approveDevicePairing",
);

if (!approvePairing) {{
  throw new Error("approveDevicePairing export was not found in the installed OpenClaw device pairing module.");
}}

const approved = await approvePairing(requestId, "/data");
if (!approved) {{
  throw new Error(`Unknown device pairing request: ${{requestId}}`);
}}
NODE_APPROVE
}}

current_gateway_url() {{
  unset OPENCLAW_GATEWAY_URL
  if [ -r "$OVERRIDE_FILE" ]; then
    set -a
    . "$OVERRIDE_FILE"
    set +a
  fi

  if [ -n "${{OPENCLAW_GATEWAY_URL:-}}" ]; then
    printf ''%s\n'' "$OPENCLAW_GATEWAY_URL"
  else
    printf ''%s\n'' "$loopback_gateway_url"
  fi
}}

print_current() {{
  local effective_gateway_url
  local mode

  effective_gateway_url="$(current_gateway_url)"
  mode="loopback"
  if [ "$effective_gateway_url" = "$public_gateway_url" ]; then
    mode="public"
  fi

  printf ''mode=%s\n'' "$mode"
  printf ''gateway_url=%s\n'' "$effective_gateway_url"
  printf ''public_gateway_url=%s\n'' "$public_gateway_url"
  printf ''public_control_url=%s\n'' "$OPENCLAW_PUBLIC_URL"
}}

persist_public() {{
  local pending_before_file
  local probe_output_file
  local request_id
  local local_device_id

  require_pairing_module
  local_device_id="$(read_local_device_id)"
  pending_before_file="$(mktemp)"
  probe_output_file="$(mktemp)"
  trap ''rm -f "$pending_before_file" "$probe_output_file"'' RETURN

  capture_cli_pending_request_ids "$pending_before_file" "$local_device_id"

  if ! run_public_cli_probe 8000 "$probe_output_file"; then
    sleep 2
    request_id="$(select_latest_cli_pending_request "$pending_before_file" "$local_device_id")"
    if [ -z "$request_id" ]; then
      echo "Public CLI pairing request was not detected automatically." >&2
      echo "Open the public gateway once manually, then retry openclaw-use-public-gateway." >&2
      cat "$probe_output_file" >&2
      exit 1
    fi

    echo "Approving public CLI pairing request for device $local_device_id: $request_id"
    approve_cli_pairing_request "$request_id"

    if ! run_public_cli_probe 15000 "$probe_output_file"; then
      echo "Public CLI pairing was approved, but validating the public gateway path still failed." >&2
      cat "$probe_output_file" >&2
      exit 1
    fi
  fi

  printf ''OPENCLAW_GATEWAY_URL=%s\n'' "$public_gateway_url" > "$OVERRIDE_FILE"
  echo "Persisted public gateway mode. Open a new SSH login shell to apply it."
  print_current
}}

persist_loopback() {{
  : > "$OVERRIDE_FILE"
  echo "Persisted loopback gateway mode. Open a new SSH login shell to apply it."
  print_current
}}

usage() {{
  cat <<''USAGE''
Usage:
  openclaw-gateway-mode current
  openclaw-gateway-mode public
  openclaw-gateway-mode loopback

The selected mode is stored for future login shells.
The public mode auto-approves the pending public CLI device pairing when needed.
USAGE
}}

command="${{1:-current}}"
case "$command" in
  current)
    print_current
    ;;
  public)
    persist_public
    ;;
  loopback)
    persist_loopback
    ;;
  -h|--help|help)
    usage
    ;;
  *)
    usage >&2
    exit 1
    ;;
esac
EOF
chmod 755 /usr/local/bin/openclaw-gateway-mode
