#!/usr/bin/env python3
"""Azure OpenAI Managed Identity token proxy."""
import http.client
import http.server
import json
import os
import socketserver
import ssl
import sys
import threading
import time
import urllib.error
import urllib.parse
import urllib.request

IMDS_TOKEN_URL = "http://169.254.169.254/metadata/identity/oauth2/token"
COGNITIVE_SERVICES_RESOURCE = "https://cognitiveservices.azure.com/"
REFRESH_MARGIN_SECONDS = 300


class TokenManager:
    def __init__(self):
        self._lock = threading.Lock()
        self._token = None
        self._expires_at = 0

    def get_token(self):
        now = time.time()
        with self._lock:
            if self._token and now < self._expires_at - REFRESH_MARGIN_SECONDS:
                return self._token
            return self._refresh()

    def _refresh(self):
        params = urllib.parse.urlencode(
            {{"api-version": "2018-02-01", "resource": COGNITIVE_SERVICES_RESOURCE}}
        )
        url = IMDS_TOKEN_URL + "?" + params
        req = urllib.request.Request(url, headers={{"Metadata": "true"}})
        with urllib.request.urlopen(req, timeout=30) as resp:
            data = json.loads(resp.read())
        self._token = data["access_token"]
        self._expires_at = int(data["expires_on"])
        remaining = self._expires_at - time.time()
        sys.stderr.write("[mi-proxy] Token refreshed, expires in %ds\n" % int(remaining))
        sys.stderr.flush()
        return self._token


token_mgr = TokenManager()


class Handler(http.server.BaseHTTPRequestHandler):
    upstream = ""

    def _proxy(self):
        if self.path == "/health":
            self.send_response(200)
            self.send_header("Content-Type", "text/plain")
            self.end_headers()
            self.wfile.write(b"ok\n")
            return

        parsed = urllib.parse.urlparse(self.upstream)
        path = parsed.path.rstrip("/") + self.path
        length = int(self.headers.get("Content-Length", "0"))
        body = self.rfile.read(length) if length > 0 else None

        hdrs = {{}}
        for k in self.headers:
            if k.lower() in ("host", "authorization", "api-key"):
                continue
            hdrs[k] = self.headers[k]
        hdrs["Authorization"] = "Bearer " + token_mgr.get_token()
        hdrs["Host"] = parsed.hostname

        port = parsed.port or (443 if parsed.scheme == "https" else 80)
        if parsed.scheme == "https":
            conn = http.client.HTTPSConnection(
                parsed.hostname, port, context=ssl.create_default_context()
            )
        else:
            conn = http.client.HTTPConnection(parsed.hostname, port)
        try:
            conn.request(self.command, path, body=body, headers=hdrs)
            resp = conn.getresponse()
            self.send_response_only(resp.status)
            for k, v in resp.getheaders():
                if k.lower() == "transfer-encoding":
                    continue
                self.send_header(k, v)
            self.end_headers()
            while True:
                chunk = resp.read(4096)
                if not chunk:
                    break
                self.wfile.write(chunk)
                self.wfile.flush()
        except Exception as exc:
            sys.stderr.write("[mi-proxy] Upstream error: %s\n" % str(exc))
            sys.stderr.flush()
            try:
                self.send_error(502, "Upstream error")
            except Exception:
                pass
        finally:
            conn.close()

    do_GET = _proxy
    do_POST = _proxy
    do_PUT = _proxy
    do_DELETE = _proxy
    do_PATCH = _proxy

    def log_message(self, fmt, *args):
        pass


class Server(socketserver.ThreadingMixIn, http.server.HTTPServer):
    daemon_threads = True
    allow_reuse_address = True


def main():
    if len(sys.argv) < 3:
        sys.stderr.write("Usage: azure-openai-mi-proxy PORT UPSTREAM_URL\n")
        sys.exit(1)
    port = int(sys.argv[1])
    Handler.upstream = sys.argv[2]
    srv = Server(("127.0.0.1", port), Handler)
    sys.stderr.write("[mi-proxy] 127.0.0.1:%d -> %s\n" % (port, Handler.upstream))
    sys.stderr.flush()
    srv.serve_forever()


if __name__ == "__main__":
    main()
